-- Local Wellness BMC mobile demo deployment: part 3 of 4
-- Loads versioned ward/zone crosswalks and routing references, then records the source checksum.
-- Generated by scripts/generate-bmc-mobile-demo-deployment.mjs. Do not edit manually.
-- Run in Supabase SQL Editor only after the current adaptive master migration parts.

begin;

select pg_catalog.pg_advisory_xact_lock(
  pg_catalog.hashtextextended('local_wellness_bmc_mobile_demo_deployment', 0)
);

do $bmc_mobile_demo_schema_preflight$
begin
  if to_regclass('governance.authorities') is null
    or to_regclass('governance.states') is null
    or to_regclass('governance.local_bodies') is null
    or to_regclass('governance.wards') is null
    or to_regclass('governance.jurisdiction_boundary_versions') is null
    or to_regclass('governance.ward_administrative_zone_membership_versions') is null
    or to_regclass('governance.ward_boundary_crosswalk_versions') is null
    or to_regclass('routing.issue_categories') is null
    or to_regclass('routing.route_rule_versions') is null then
    raise exception using
      errcode = '55000',
      message = 'BMC_MOBILE_DEMO_SCHEMA_NOT_CURRENT',
      hint = 'Run supabase/master.part-1.sql and then supabase/master.part-2.sql before this deployment.';
  end if;
end;
$bmc_mobile_demo_schema_preflight$;

-- SECTION: versioned ward crosswalks and governance routing references
