-- SECTION: generated governance source checksum
do $bmc_governance_seed_checksum$
declare
  affected_rows integer;
begin
  update governance.import_batches
  set generated_seed_sha256 = '1a696300a017ad680ade3fed25a0333d3b09c6ead902cfb30ddd4b9b9074e65b'
  where id = 'ac1a5451-f0a0-5faa-91b0-2652f125969b'
    and dataset_key = 'bmc_demo_governance'
    and dataset_version = 'MUMBAI_BMC_DEMO_BOOTSTRAP_DATA_v1'
    and (
      generated_seed_sha256 is null
      or generated_seed_sha256 = '1a696300a017ad680ade3fed25a0333d3b09c6ead902cfb30ddd4b9b9074e65b'
    );

  get diagnostics affected_rows = row_count;

  if affected_rows <> 1 then
    raise exception using
      errcode = '55000',
      message = 'Expected exactly one matching BMC governance import batch while recording the generated seed checksum.';
  end if;
end
$bmc_governance_seed_checksum$;

do $bmc_mobile_demo_part_3_verify$
begin
  if (
    select count(*)
    from governance.ward_administrative_zone_membership_versions as membership
    inner join governance.wards as ward on ward.id = membership.operational_ward_id
    where ward.local_body_id = 'fa1e71b4-01e3-5e72-92e8-1476eec1adcd'
  ) <> 26 or (
    select count(*)
    from governance.ward_boundary_crosswalk_versions as crosswalk
    inner join governance.wards as ward on ward.id = crosswalk.operational_ward_id
    where ward.local_body_id = 'fa1e71b4-01e3-5e72-92e8-1476eec1adcd'
  ) <> 26 or (
    select count(*)
    from governance.complaint_routing_references
    where rule_code like 'BMC_R%'
  ) <> 14 then
    raise exception using errcode = '55000', message = 'BMC_MOBILE_DEMO_CROSSWALK_COUNT_INVALID';
  end if;
end;
$bmc_mobile_demo_part_3_verify$;

commit;
